example.code:
.md3-glass-surface {
  background: color-mix(in srgb, var(--md-sys-color-surface) 78%, transparent);
  backdrop-filter: blur(10px) saturate(1.08);
  border: 1px solid color-mix(in srgb, var(--md-sys-color-outline-variant) 46%, transparent);
  box-shadow: var(--md-sys-elevation-level2);
}

.md3-glass-surface .text,
.md3-glass-surface .label {
  color: var(--md-sys-color-on-surface);
}

.md3-interactive:focus-visible {
  outline: 3px solid var(--md-sys-color-primary);
  outline-offset: 2px;
}

.md3-touch-target {
  min-width: 48px;
  min-height: 48px;
}

.md3-state-layer {
  background-color: var(--md-sys-color-on-surface);
  opacity: var(--md-sys-state-opacity-hover);
}

.md3-interactive:focus-visible {
  outline: 2px solid var(--md-sys-color-primary);
  outline-offset: 2px;
}

.md3-surface {
  background: var(--md-sys-color-surface-container);
  box-shadow: var(--md-sys-elevation-level2);
}

.md3-surface-emphasis {
  background: var(--md-sys-color-surface-container-high);
  box-shadow: var(--md-sys-elevation-level3);
}

.md3-motion {
  transition-duration: var(--md-sys-motion-duration-medium);
  transition-timing-function: var(--md-sys-motion-easing-standard);
}

@media (prefers-reduced-motion: reduce) {
  .md3-motion {
    transition-duration: 0ms;
    animation-duration: 0ms;
  }
}
